/**
 * Describes a payload sent to an entrypoint during an attack.
 */
export interface EntrypointPayload {
    /**
     * Name of the payload, if applicable.
     */
    name?: string | null;
    /**
     * Type of the payload.
     */
    type?: 'HTTP_BODY' | 'HTTP_COOKIE' | 'HTTP_HEADER_NAME' | 'HTTP_HEADER_VALUE' | 'HTTP_OTHER' | 'HTTP_PARAMETER_NAME' | 'HTTP_PARAMETER_VALUE' | 'HTTP_URL' | 'UNKNOWN';
    /**
     * Value of the payload.
     */
    value?: string;
}
